  const f=document.querySelector('#modalForm');
  const selectedIds=()=>f.type.value==='individual'?(f.studentId.value?[f.studentId.value]:[]):(state.groups.find(g=>g.id===f.groupId.value)?.studentIds||[]);
  const renderAttendance=()=>{const ids=selectedIds();document.querySelector('#attendanceRows').innerHTML=ids.length?ids.map(sid=>{const a=l.attendance?.[sid]||{status:'present',note:''};const s=state.students.find(x=>x.id===sid),position=subscriptionPositionForLesson(l,sid),used=Math.max(0,(s?.total||0)-(s?.remaining||0));return `<div class="attendance-row"><strong>${esc(studentName(sid))}</strong><span class="lesson-number">${position?`${position.number} из ${position.total}`:`Следующий: ${Math.min(used+1,s?.total||1)} из ${s?.total||1}`}</span><select name="attendance_${sid}" class="filter"><option value="present" ${a.status!=='absent'?'selected':''}>Присутствовал — списать</option><option value="absent" ${a.status==='absent'?'selected':''}>Отсутствовал — тоже списать</option></select><input name="absenceNote_${sid}" value="${esc(a.note||'')}" placeholder="Причина отсутствия"></div>`}).join(''):'<div class="empty compact">Сначала выберите ученика или группу</div>'};
  const toggle=()=>{const individual=f.type.value==='individual';document.querySelector('#studentField').style.display=individual?'grid':'none';document.querySelector('#groupField').style.display=individual?'none':'grid';renderAttendance()};
