function normalizedWords(text){const aliases={маша:'мария',маши:'мария',машу:'мария',даша:'дарья',даши:'дарья',даше:'дарья',дашу:'дарья',саша:'александр',катя:'екатерина',лена:'елена',дима:'дмитрий',макс:'максим',соня:'софия',настя:'анастасия'};return text.toLowerCase().replace(/ё/g,'е').replace(/[.,!?—:;]+/g,' ').split(/\s+/).filter(Boolean).map(w=>aliases[w]||w)}
