function parseScheduleSlots(text){const dayMap={понедельник:0,пн:0,вторник:1,вт:1,среда:2,ср:2,четверг:3,чт:3,пятница:4,пт:4,суббота:5,сб:5,воскресенье:6,вс:6},matches=[...text.matchAll(/(?:^|[\s,;])(понедельник|вторник|среда|четверг|пятница|суббота|воскресенье|пн|вт|ср|чт|пт|сб|вс)(?=$|[\s,;])/gi)],slots=[];for(let i=0;i<matches.length;i++){const from=(matches[i].index||0)+matches[i][0].length,to=i+1<matches.length?matches[i+1].index:text.length,part=text.slice(from,to),tm=part.match(/\b([01]?\d|2[0-3])[.:]([0-5]\d)\b/);if(tm)slots.push({day:dayMap[matches[i][1].toLowerCase()],time:normalizeTime(tm[0])})}if(slots.length===matches.length&&slots.length)return slots;const days=parseWeekdays(text),times=parseExplicitTimes(text);if(!days.length)return[];if(times.length===1)return days.map(day=>({day,time:times[0]}));if(times.length>=days.length)return days.map((day,i)=>({day,time:times[i]}));return[]}
