function setSubscriptionStart(student,date,position){if(position.number<1||position.total<1||position.total>12||position.number>position.total)return 'Номер урока и размер абонемента должны быть от 1 до 12, а номер урока не может быть больше размера абонемента.';let lesson=findStudentLesson(student.id,date),created=false;if(!lesson){const day=(new Date(date+'T12:00:00').getDay()+6)%7,slot=student.scheduleSlots?.find(x=>x.day===day),time=slot?.time||student.time||'16:00';lesson={id:uid(),date,start:time,end:`${String(Math.min(parseInt(time)+1,23)).padStart(2,'0')}:00`,type:'individual',studentId:student.id,groupId:'',teacher:student.teacher,status:'planned',note:'Создано при настройке абонемента через AI-помощника',attendance:{[student.id]:{status:'present',note:''}},chargedStudentIds:[]};state.lessons.push(lesson);created=true}const previous=student.remaining;student.total=position.total;student.subscriptionStartDate=date;student.subscriptionStartNumber=position.number;const charged=state.lessons.filter(l=>l.date>=date&&(l.chargedStudentIds||[]).includes(student.id)).length;student.remaining=Math.max(0,position.total-(position.number-1)-charged);student.history.push({id:uid(),date:new Date().toISOString(),delta:student.remaining-previous,reason:`Отсчёт абонемента: ${position.number} из ${position.total} с ${date}`});const next=state.lessons.filter(l=>l.id!==lesson.id&&l.date>=date&&lessonCountsForSubscription(l,student.id)).sort((a,b)=>a.date.localeCompare(b.date)||a.start.localeCompare(b.start))[0],nextPosition=next?subscriptionPositionForLesson(next,student.id):null;return `Готово. Абонемент: ${student.first} ${student.last}. ${fmtDate(new Date(date+'T12:00:00'))} — ${position.number}-й урок из ${position.total}.${created?' Занятие на эту дату создано автоматически.':''}${next&&nextPosition?` Следующее занятие ${fmtDate(new Date(next.date+'T12:00:00'))} — ${nextPosition.number}-е из ${nextPosition.total}.`:''}`}
function extractNewStudentName(raw){return raw.split(/\s+(?=(?:у\s+не(?:го|ё|е)|(?:только\s+)?(?:один|одна|одно|1)\s+(?:урок|занятие)|пн|вт|ср|чт|пт|сб|вс|понедельник|вторник|среда|четверг|пятница|суббота|воскресенье|преподаватель|учитель|дни|время|формат|абонемент|контакт)(?:\s|,|$)|\d{1,2}[.\/-]\d{1,2}(?:[.\/-]\d{2,4})?(?:\s|,|$)|(?:[01]?\d|2[0-3])[.:][0-5]\d(?:\s|,|$))/i)[0].trim()}
